import { Request, Response, } from 'express'
import PdfPrinter from 'pdfmake'
import { mailer } from '../../../config'
import { Attachment } from 'nodemailer/lib/mailer'
import path from 'path'
import { AddProposalForBuildingService } from '../service/add-proposal-for-building.service'

export const createAddProposalController = ({ addProposalForBuildingService }: { addProposalForBuildingService: AddProposalForBuildingService }) => (req: Request, res: Response) => {
  const { ownerId, contactId, message, amount } = req.body
  return addProposalForBuildingService
    .add(req.params.buildingId, { ownerId, contactId, message, amount })
    .then(() => {
      res.status(201).json()
    })
}

const sendProposalEmail = () => {
  return createPdf('Romo Rampa 295, TEST_PORTO', '123456789', 1000)
    .then(pdf => {
      return new Promise((resolve, reject) => {
        const chunks = []
        pdf.on('data', (chunk) => {
          console.log('chunk received')
          chunks.push(chunk)
        })

        pdf.on('end', () => {
          const pdfBuffer = Buffer.concat(chunks)
          console.log('stream end', pdfBuffer.length)
          const message = createMessage({
              email: 'flipper@email.test',
              firstName: 'FlipperName',
              lastName: 'FlipperLastName'
            }, {
              to: 'owner@email.test',
              subject: emailCopies['es']['mailSubject'],
              html: 'email content',
              text: 'email content'
            },
            pdfBuffer
          )
          mailer.transporter.sendMail(message).then(resolve).catch(reject)
        })

        pdf.end()
      })
    })
}

