function createMessage(
  from: { firstName: string; lastName: string; email: string },
  data: { to: any; subject: any; text: any; html: any },
  pdfContent: any) {
  const { to, subject, text, html } = data

  const attachment: Attachment = {
    content: pdfContent,
    filename: 'propuesta.pdf'
  }

  return {
    to,
    bcc: 'daniel.leiva@mkpremium.com',
    replyTo: `${from.firstName} ${from.lastName}<${from.email}>`,
    from: `${from.firstName} ${from.lastName}<${process.env.MAILER_USER}>`,
    subject,
    html,
    text,
    attachments: [ attachment ]
  }
}
